import React from 'react';
import { useNavigate } from 'react-router-dom';

function Home() {
  const navigate = useNavigate();
  return (
    <div className="relative bg-gradient-to-br from-[#18181b] via-[#23232a] to-[#1e1b4b] min-h-screen text-white overflow-x-hidden">
      {/* Floating Gradient Accent */}
      <div className="absolute -top-32 left-1/2 -translate-x-1/2 w-[600px] h-[300px] bg-gradient-to-r from-fuchsia-500/20 via-blue-500/10 to-transparent rounded-full blur-3xl animate-float" style={{zIndex:0}} />
      {/* Hero Section */}
      <section className="flex flex-col items-center justify-center pt-20 pb-12 animate-fade-in-up relative z-10">
        <span className="mb-4 px-4 py-1 rounded-full bg-gradient-to-r from-purple-600 to-indigo-500 text-xs font-semibold shadow-lg animate-pulse">Powered by Cohere AI</span>
        <h1 className="text-5xl md:text-6xl font-extrabold text-center mb-4 bg-gradient-to-r from-fuchsia-500 via-purple-400 to-blue-500 bg-clip-text text-transparent animate-gradient-x">
          A Fast AI. <span className="bg-gradient-to-r from-purple-400 to-blue-500 bg-clip-text text-transparent">Scalable Code.</span>
        </h1>
        <p className="text-lg md:text-xl text-gray-300 text-center max-w-2xl mb-8 animate-fade-in">
          Our technology performing fast AI generation and it has guaranteed AI-based code generation. Proof of Quality, its algorithm enables unlimited speeds.
        </p>
        <div className="flex gap-4 mb-8">
          <button
            className="bg-gradient-to-r from-fuchsia-500 via-purple-500 to-blue-500 text-white px-6 py-2 rounded-lg font-semibold shadow-lg hover:scale-105 hover:shadow-lg hover:from-purple-600 hover:to-blue-600 transition duration-300"
            onClick={() => navigate('/generator')}
          >
            Get started
          </button>
          <button
            className="bg-[#23232a] text-white px-6 py-2 rounded-lg font-semibold border border-purple-700 hover:bg-purple-900/60 hover:border-fuchsia-500 transition duration-300"
            onClick={() => navigate('/docs')}
          >
            Documentation
          </button>
        </div>
        {/* Stats Section with animated gradient rings */}
        <div className="flex flex-wrap justify-center gap-6 mt-4 relative z-10">
          {[
            { value: '10M+', label: 'Lines Generated', color: 'from-fuchsia-400 to-purple-500' },
            { value: '50K+', label: 'Developers', color: 'from-blue-400 to-fuchsia-500' },
            { value: '25+', label: 'Languages', color: 'from-green-400 to-blue-500' },
            { value: '99.5%', label: 'Success Rate', color: 'from-yellow-400 to-fuchsia-400' },
          ].map((stat, i) => (
            <div
              key={stat.label}
              className="relative group bg-[#23232a] rounded-xl p-6 min-w-[180px] text-center border border-purple-800 shadow-lg hover:scale-110 hover:border-fuchsia-500 transition duration-300 animate-pop-fade"
              style={{ animationDelay: `${0.1 + i * 0.1}s` }}
            >
              <div className={`absolute -inset-2 z-0 rounded-2xl blur-xl opacity-60 group-hover:opacity-90 transition duration-300 pointer-events-none bg-gradient-to-r ${stat.color} animate-gradient-x`} />
              <div className="relative z-10 text-fuchsia-400 text-2xl font-bold animate-bounce">{stat.value}</div>
              <div className="relative z-10 text-gray-400 text-sm">{stat.label}</div>
            </div>
          ))}
        </div>
      </section>

      {/* Features Section */}
      <section className="relative max-w-5xl mx-auto py-12 animate-fade-in-up z-10">
        {/* Floating Accent for Features */}
        <div className="absolute -top-24 left-1/2 -translate-x-1/2 w-[500px] h-[200px] bg-gradient-to-r from-blue-500/20 via-fuchsia-500/10 to-transparent rounded-full blur-3xl animate-float2" style={{zIndex:0}} />
        <h2 className="text-3xl md:text-4xl font-extrabold text-center mb-4 bg-gradient-to-r from-fuchsia-400 to-blue-500 bg-clip-text text-transparent animate-gradient-x relative z-10">
          Why Choose <span className="bg-gradient-to-r from-purple-400 to-blue-500 bg-clip-text text-transparent">CodeGen AI?</span>
        </h2>
        <p className="text-center text-gray-300 mb-10 animate-fade-in relative z-10">
          Experience the future of code generation with Cohere's cutting-edge AI technology
        </p>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8 relative z-10">
          {[
            { title: '< /> Smart Code Generation', desc: `Generate clean, production-ready code in multiple programming languages with Cohere's advanced AI models.`, color: 'from-fuchsia-400 to-blue-500' },
            { title: '⚡ Lightning Fast', desc: 'Get your code generated in seconds, not hours. Optimized for speed and efficiency.', color: 'from-blue-400 to-fuchsia-500' },
            { title: '🛡️ Secure & Private', desc: 'Your code and data are protected with enterprise-grade security and privacy measures.', color: 'from-green-400 to-blue-500' },
            { title: '🎯 Customizable Output', desc: 'Tailor the generated code to match your coding style and project requirements.', color: 'from-yellow-400 to-fuchsia-400' },
          ].map((feature, i) => (
            <div
              key={feature.title}
              className="relative group bg-[#23232a] rounded-xl p-6 border border-purple-800 shadow-lg hover:scale-105 hover:border-fuchsia-500 transition duration-300 animate-pop-fade"
              style={{ animationDelay: `${0.1 + i * 0.1}s` }}
            >
              <div className={`absolute -inset-2 z-0 rounded-2xl blur-xl opacity-50 group-hover:opacity-80 transition duration-300 pointer-events-none bg-gradient-to-r ${feature.color} animate-gradient-x`} />
              <div className="relative z-10 text-fuchsia-400 font-bold mb-2">{feature.title}</div>
              <div className="relative z-10 text-gray-300">{feature.desc}</div>
            </div>
          ))}
        </div>
      </section>

      {/* Call to Action Section */}
      <section className="flex flex-col items-center justify-center py-16 animate-fade-in-up">
        <h2 className="text-3xl md:text-4xl font-extrabold text-center mb-4 bg-gradient-to-r from-fuchsia-400 to-blue-500 bg-clip-text text-transparent animate-gradient-x">
          Ready to Generate Your <span className="bg-gradient-to-r from-purple-400 to-blue-500 bg-clip-text text-transparent">First Code?</span>
        </h2>
        <p className="text-center text-gray-300 mb-6 max-w-xl animate-fade-in">
          Join thousands of developers who are already using CodeGen AI to accelerate their development workflow.
        </p>
        <button
          className="bg-gradient-to-r from-fuchsia-500 via-purple-500 to-blue-500 text-white px-8 py-3 rounded-lg font-semibold shadow-lg hover:scale-110 hover:shadow-lg hover:from-purple-600 hover:to-blue-600 transition duration-300 text-lg"
          onClick={() => navigate('/generator')}
        >
          Get Started Now
        </button>
      </section>

      {/* Animations (Tailwind custom classes) */}
      <style>{`
        .animate-fade-in-up {
          animation: fadeInUp 1s cubic-bezier(0.4, 0, 0.2, 1) both;
        }
        .animate-fade-in {
          animation: fadeIn 1.2s cubic-bezier(0.4, 0, 0.2, 1) both;
        }
        .animate-gradient-x {
          background-size: 200% 200%;
          animation: gradientX 3s ease-in-out infinite;
        }
        .animate-pop-fade {
          animation: popFadeIn 1s cubic-bezier(0.4, 0, 0.2, 1) both;
        }
        @keyframes fadeInUp {
          from { opacity: 0; transform: translateY(40px); }
          to { opacity: 1; transform: translateY(0); }
        }
        @keyframes fadeIn {
          from { opacity: 0; }
          to { opacity: 1; }
        }
        @keyframes gradientX {
          0%, 100% { background-position: left center; }
          50% { background-position: right center; }
        }
        @keyframes popFadeIn {
          0% { opacity: 0; transform: translateY(40px) scale(0.95); }
          60% { opacity: 1; transform: translateY(-8px) scale(1.05); }
          100% { opacity: 1; transform: translateY(0) scale(1); }
        }
        .animate-float {
          animation: floatY 7s ease-in-out infinite alternate;
        }
        .animate-float2 {
          animation: floatY2 9s ease-in-out infinite alternate;
        }
        @keyframes floatY {
          0% { transform: translateY(0); }
          100% { transform: translateY(30px); }
        }
        @keyframes floatY2 {
          0% { transform: translateY(0); }
          100% { transform: translateY(20px); }
        }
      `}</style>
    </div>
  );
}

export default Home;
